using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Set up options with a known type context
var options = new JsonSerializerOptions
{
    TypeInfoResolver = MyContext.Default
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// Round-trip using the typed metadata
var json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

Person deserialized = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Deserialized: {deserialized}");

// 2) Probe without throwing: TryGetTypeInfo returns false if metadata isn't available
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
{
    Console.WriteLine($"\nTryGetTypeInfo(Person) succeeded: {found!.Type.Name}");
}

// This type is NOT in our context, so it returns false instead of throwing
if (options.TryGetTypeInfo(typeof(Uri), out _))
{
    Console.WriteLine("Unexpected: Uri metadata found");
}
else
{
    Console.WriteLine("TryGetTypeInfo(Uri) returned false — no metadata, no exception.");
}

// Records used in the demo
public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
internal partial class MyContext : JsonSerializerContext;

